// menu-ar.service.ts
import { Injectable } from '@angular/core';
import { BaseService } from '../Base/base.service';

export interface MenuPdf {
  id: string;
  menu_id: string;
  restaurant_id: string;
  file_path: string;
  mind_file_path: string | null;
  page_count: number;
  status: 'uploading' | 'processing' | 'ready' | 'error';
  created_at: string;
  pdf_url?: string; // calcolato client-side
}

export interface MenuPdfZone {
  id: string;
  menu_pdf_id: string;
  dish_id: string | null;
  page_number: number;
  x: number;
  y: number;
  width: number;
  height: number;
  created_at: string;
  // join dati piatto (calcolati client-side)
  dish_name?: string;
  dish_price?: number;
  dish_image_url?: string | null;
}

export interface DishOption {
  id: string;
  name: string;
  base_price: number;
  category_name?: string;
  image_url?: string | null;
}

// ─── Bucket e path costanti ───────────────────────────────
const BUCKET = 'restaurant-images';
const PDF_FOLDER = 'menu-pdfs'; // sottocartella dentro restaurant-images

@Injectable({ providedIn: 'root' })
export class MenuArService extends BaseService<MenuPdf> {

  protected getTableName(): string { return 'menu_pdfs'; }

  private get db() { return this.supabaseService.getSupabaseClient(); }

  // ── Override loadData: idrata gli URL dopo il caricamento ──
  override async loadData(additionalFilters?: Record<string, any>): Promise<void> {
    await super.loadData(additionalFilters);
    this.dataSubject.next(
      this.dataSubject.value.map(pdf => this.hydratePdfUrl(pdf))
    );
  }

  async loadPdfsByMenu(menuId: string): Promise<void> {
    await this.loadData({ menu_id: menuId });
  }

  getPdfsByMenu(menuId: string): MenuPdf[] {
    return this.data.filter(p => p.menu_id === menuId);
  }

  // ══════════════════════════════════════════════════════════
  // UPLOAD PDF
  // ══════════════════════════════════════════════════════════

  async uploadMenuPdf(menuId: string, file: File): Promise<MenuPdf | null> {
    const restaurantId = await this.getCurrentRestaurantId();
    if (!restaurantId) return null;

    try {
      // 1. Percorso nel bucket restaurant-images
      const timestamp = Date.now();
      const safeName = file.name
        .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
        .replace(/[^a-zA-Z0-9.\-_]/g, '_').replace(/_+/g, '_').toLowerCase();
      const filePath = `${PDF_FOLDER}/${restaurantId}/${menuId}/${timestamp}_${safeName}`;

      // 2. Upload su Storage
      const { error: uploadError } = await this.db.storage
        .from(BUCKET)
        .upload(filePath, file, { cacheControl: '3600', upsert: false });

      if (uploadError) throw uploadError;

      // 3. Conta pagine tramite pdf.js
      const pageCount = await this.countPdfPages(file);

      // 4. Crea record DB — BaseService.create() aggiunge restaurant_id, created_at, updated_at
      const result = await this.create({
        menu_id: menuId,
        file_path: filePath,
        mind_file_path: null,
        page_count: pageCount,
        status: 'uploading' as const,
      });

      return result ? this.hydratePdfUrl(result) : null;
    } catch (err) {
      this.handleError('uploadMenuPdf', err);
      return null;
    }
  }

  async updatePdfStatus(
    pdfId: string,
    status: MenuPdf['status'],
    mindFilePath?: string
  ): Promise<boolean> {
    const updates: Partial<MenuPdf> = { status };
    if (mindFilePath) updates.mind_file_path = mindFilePath;
    return this.update(pdfId, updates);
  }

  async deleteMenuPdf(pdfId: string, filePath: string): Promise<boolean> {
    try {
      await this.db.from('menu_pdf_zones').delete().eq('menu_pdf_id', pdfId);
      await this.db.storage.from(BUCKET).remove([filePath]).catch(() => {});
      return this.delete(pdfId);
    } catch (err) {
      this.handleError('deleteMenuPdf', err);
      return false;
    }
  }

  getPdfPublicUrl(filePath: string): string {
    return this.db.storage.from(BUCKET).getPublicUrl(filePath).data.publicUrl;
  }

  private hydratePdfUrl(pdf: MenuPdf): MenuPdf {
    return { ...pdf, pdf_url: pdf.file_path ? this.getPdfPublicUrl(pdf.file_path) : undefined };
  }

  // ══════════════════════════════════════════════════════════
  // ZONE
  // ══════════════════════════════════════════════════════════

  async getZonesByPdf(pdfId: string): Promise<MenuPdfZone[]> {
    const { data, error } = await this.run(
      this.db
        .from('menu_pdf_zones')
        .select('*, dishes(id, name, base_price, image_url)')
        .eq('menu_pdf_id', pdfId)
        .order('page_number')
    );
    if (error) { this.handleError('getZonesByPdf', error); return []; }
    return ((data as any[]) || []).map(z => ({
      ...z,
      dish_name: z.dishes?.name,
      dish_price: z.dishes?.base_price,
      dish_image_url: z.dishes?.image_url,
      dishes: undefined,
    }));
  }

  async saveZone(
    zone: Omit<MenuPdfZone, 'id' | 'created_at' | 'dish_name' | 'dish_price' | 'dish_image_url'>
  ): Promise<MenuPdfZone | null> {
    const { data, error } = await this.run(
      this.db
        .from('menu_pdf_zones')
        .insert({ ...zone, created_at: new Date().toISOString() })
        .select()
        .single()
    );
    if (error) { this.handleError('saveZone', error); return null; }
    return data as unknown as MenuPdfZone;
  }

  async updateZone(
    zoneId: string,
    updates: Partial<Pick<MenuPdfZone, 'dish_id' | 'x' | 'y' | 'width' | 'height'>>
  ): Promise<boolean> {
    const { error } = await this.run(
      this.db.from('menu_pdf_zones').update(updates).eq('id', zoneId)
    );
    if (error) { this.handleError('updateZone', error); return false; }
    return true;
  }

  async deleteZone(zoneId: string): Promise<boolean> {
    const { error } = await this.run(
      this.db.from('menu_pdf_zones').delete().eq('id', zoneId)
    );
    if (error) { this.handleError('deleteZone', error); return false; }
    return true;
  }

  // ══════════════════════════════════════════════════════════
  // PDF.JS — rendering pagine
  // ══════════════════════════════════════════════════════════

  async countPdfPages(file: File): Promise<number> {
    try {
      const lib = await this.loadPdfJs();
      const buf = await file.arrayBuffer();
      const pdf = await lib.getDocument({ data: buf }).promise;
      return pdf.numPages;
    } catch { return 1; }
  }

  async renderPdfPage(
    pdfUrl: string,
    pageNumber: number,
    scale = 1.5
  ): Promise<{ canvas: HTMLCanvasElement; width: number; height: number } | null> {
    try {
      const lib = await this.loadPdfJs();
      const pdf = await lib.getDocument(pdfUrl).promise;
      const page = await pdf.getPage(pageNumber);
      const viewport = page.getViewport({ scale });

      const canvas = document.createElement('canvas');
      canvas.width = viewport.width;
      canvas.height = viewport.height;
      await page.render({ canvasContext: canvas.getContext('2d')!, viewport }).promise;
      return { canvas, width: viewport.width, height: viewport.height };
    } catch (err) {
      this.handleError('renderPdfPage', err);
      return null;
    }
  }

  private loadPdfJs(): Promise<any> {
    return new Promise((resolve, reject) => {
      if ((window as any)['pdfjsLib']) { resolve((window as any)['pdfjsLib']); return; }
      const script = document.createElement('script');
      script.src = 'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.min.js';
      script.onload = () => {
        const lib = (window as any)['pdfjsLib'];
        lib.GlobalWorkerOptions.workerSrc =
          'https://cdnjs.cloudflare.com/ajax/libs/pdf.js/3.11.174/pdf.worker.min.js';
        resolve(lib);
      };
      script.onerror = reject;
      document.head.appendChild(script);
    });
  }
}